import React, {useState, useRef} from 'react';
import {Sparkles} from 'lucide-react';
import BackgroundFrame from './BackgroundFrame';
import DateCounter from './DateCounter';
import MoodSelector from './MoodSelector';
import Brightness from './Brightness';
import Volume from './Volume';
import Speed from './Speed';
import HeartsCounter from './HeartsCounter';
import SparkleToggle from './SparkleToggle';
import ThemeSelection from './ThemeSelection';
import EnergyInput from './EnergyInput';
import IconPicker from './IconPicker';

function CuteParameterCard() {
    const [params, setParams] = useState({
        brightness: 75,
        volume: 60,
        speed: 3,
        hearts: 5,
        sparkle: true,
        theme: 'pink',
        energy: 80,
        cuteness: 100,
        dateCount: 0,
        mood: null,
        pendingMood: null
    });

    const [paramIcons, setParamIcons] = useState({
        brightness: 'Sun',
        volume: 'Volume2',
        speed: 'Zap',
        hearts: 'Heart',
        sparkle: 'Sparkles',
        theme: 'Moon',
        energy: 'Zap',
        dateCount: 'Calendar',
        mood: 'Star'
    });

    const [iconPickerOpen, setIconPickerOpen] = useState(null);
    const [pickerPosition, setPickerPosition] = useState({top: 0, left: 0});
    const buttonRefs = useRef({});

    const updateParam = (key, value) => {
        setParams(prev => ({...prev, [key]: value}));
    };

    const updateIcon = (paramKey, iconName) => {
        setParamIcons(prev => ({...prev, [paramKey]: iconName}));
        setIconPickerOpen(null);
    };

    const handleDateClick = () => {
        updateParam('dateCount', params.dateCount + 1);
    };

    const handleMoodClick = (mood) => {
        if (params.pendingMood === mood) {
            updateParam('mood', mood);
            updateParam('pendingMood', null);
        } else {
            updateParam('pendingMood', mood);
            if (params.mood !== mood) {
                updateParam('mood', null);
            }
        }
    };

    const handleIconClick = (paramKey) => {
        if (iconPickerOpen === paramKey) {
            setIconPickerOpen(null);
            return;
        }

        const button = buttonRefs.current[paramKey];
        if (button) {
            const rect = button.getBoundingClientRect();
            setPickerPosition({
                top: rect.bottom + window.scrollY + 8,
                left: rect.left + window.scrollX
            });
            setIconPickerOpen(paramKey);
        }
    };

    return (
        <BackgroundFrame theme={params.theme}>
            {/* Header */}
            <div className="text-center mb-6">
                <div className="flex items-center justify-center gap-2 mb-2">
                    <Sparkles className="text-pink-500" size={24}/>
                    <h2 className="text-2xl font-bold bg-gradient-to-r from-pink-500 to-purple-500 bg-clip-text text-transparent">
                        可爱参数面板
                    </h2>
                    <Sparkles className="text-purple-500" size={24}/>
                </div>
                <p className="text-sm text-gray-600">调整你的专属设置 ♡</p>
                <p className="text-xs text-pink-400 mt-1">点击图标可更换哦 ~</p>
            </div>

            {/* Individual Components */}
            <DateCounter
                dateCount={params.dateCount}
                onDateClick={handleDateClick}
                paramIcons={paramIcons}
                onIconClick={handleIconClick}
                buttonRefs={buttonRefs}
            />

            <MoodSelector
                currentMood={params.mood}
                pendingMood={params.pendingMood}
                onMoodClick={handleMoodClick}
                paramIcons={paramIcons}
                onIconClick={handleIconClick}
                buttonRefs={buttonRefs}
            />

            <Brightness
                brightness={params.brightness}
                onBrightnessChange={(value) => updateParam('brightness', value)}
                paramIcons={paramIcons}
                onIconClick={handleIconClick}
                buttonRefs={buttonRefs}
            />

            <Volume
                volume={params.volume}
                onVolumeChange={(value) => updateParam('volume', value)}
                paramIcons={paramIcons}
                onIconClick={handleIconClick}
                buttonRefs={buttonRefs}
            />

            <Speed
                speed={params.speed}
                onSpeedChange={(value) => updateParam('speed', value)}
                paramIcons={paramIcons}
                onIconClick={handleIconClick}
                buttonRefs={buttonRefs}
            />

            <HeartsCounter
                hearts={params.hearts}
                onHeartsChange={(value) => updateParam('hearts', value)}
                paramIcons={paramIcons}
                onIconClick={handleIconClick}
                buttonRefs={buttonRefs}
            />

            <SparkleToggle
                sparkle={params.sparkle}
                onSparkleChange={(value) => updateParam('sparkle', value)}
                paramIcons={paramIcons}
                onIconClick={handleIconClick}
                buttonRefs={buttonRefs}
            />

            <ThemeSelection
                theme={params.theme}
                onThemeChange={(value) => updateParam('theme', value)}
                paramIcons={paramIcons}
                onIconClick={handleIconClick}
                buttonRefs={buttonRefs}
            />

            <EnergyInput
                energy={params.energy}
                onEnergyChange={(value) => updateParam('energy', value)}
                paramIcons={paramIcons}
                onIconClick={handleIconClick}
                buttonRefs={buttonRefs}
            />

            {/* Footer */}
            <div className="text-center pt-4">
                <p className="text-xs text-gray-500">♡ 愿你每天都充满快乐 ♡</p>
            </div>

            {/* Icon Picker Portal */}
            {iconPickerOpen && (
                <IconPicker
                    paramKey={iconPickerOpen}
                    currentIcon={paramIcons[iconPickerOpen]}
                    onSelect={updateIcon}
                    onClose={() => setIconPickerOpen(null)}
                    position={pickerPosition}
                />
            )}
        </BackgroundFrame>
    );
}

export default CuteParameterCard;
